1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_THRESHOLD = 5;
5	const HIGH_ENCHANTMENT_RATE = 0.3;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const LOYALTY_RATE = 0.2;
8	const BLOCK_SIZE = 3;
9	const BLOCK_PREMIUM = 60;
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	type Item = { type: string; cursed?: boolean; enchantment?: number };
21	type Step = { op: "quote"; items: Item[] };
22	type Customer = { yearsWithMHPCO: number };
23	type Scenario = { customer: Customer; steps: Step[] };
24	type QuoteResult = { premium: number };
25	type ScenarioOutput = { results: QuoteResult[] };
26	
27	const groupCountsByType = (items: Item[]): Map<string, number> => {
28	  const counts = new Map<string, number>();
29	  for (const { type } of items) {
30	    counts.set(type, (counts.get(type) ?? 0) + 1);
31	  }
32	  return counts;
33	};
34	
35	const basePremiumForGroup = (type: string, count: number): number => {
36	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
37	  return count * BASE_PREMIUM[type];
38	};
39	
40	const basePremiumFor = (items: Item[]): number =>
41	  Array.from(groupCountsByType(items)).reduce(
42	    (total, [type, count]) => total + basePremiumForGroup(type, count),
43	    0,
44	  );
45	
46	const curseSurchargeFor = (item: Item): number =>
47	  item.cursed ? BASE_PREMIUM[item.type] * CURSE_RATE : 0;
48	
49	const highEnchantmentSurchargeFor = (item: Item): number =>
50	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
51	    ? BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_RATE
52	    : 0;
53	
54	const ITEM_SURCHARGES: Array<(item: Item) => number> = [
55	  curseSurchargeFor,
56	  highEnchantmentSurchargeFor,
57	];
58	
59	const surchargesForItem = (item: Item): number =>
60	  ITEM_SURCHARGES.reduce((sum, surcharge) => sum + surcharge(item), 0);
61	
62	const itemSurchargesFor = (items: Item[]): number =>
63	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
64	
65	const loyaltyDiscountFor = (basePremium: number, customer: Customer): number =>
66	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
67	    ? basePremium * LOYALTY_RATE
68	    : 0;
69	
70	const premiumFor = (items: Item[], customer: Customer): number => {
71	  const basePremium = basePremiumFor(items);
72	  const itemSurcharges = itemSurchargesFor(items);
73	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
74	  const loyaltyDiscount = loyaltyDiscountFor(basePremium, customer);
75	  return Math.ceil(
76	    basePremium +
77	      itemSurcharges +
78	      firstInsuranceSurcharge -
79	      loyaltyDiscount +
80	      PROCESSING_FEE,
81	  );
82	};
83	
84	const quoteStep = ({ items }: Step, customer: Customer): QuoteResult => ({
85	  premium: premiumFor(items, customer),
86	});
87	
88	export const runScenario = (input: Scenario): ScenarioOutput => ({
89	  results: input.steps.map((step) => quoteStep(step, input.customer)),
90	});
